  static bool isLand(double lat, double lon) {
    // Map latitude (-90 to 90) to row (0 to 119)
    // Map longitude (-180 to 180) to col (0 to 239)
    int row = ((90 - lat) / 180 * 119).round().clamp(0, 119);
    int col = ((lon + 180) / 360 * 239).round().clamp(0, 239);

    return maskRows[row][col] == "1";
  }
